mapper.select:
select a.id, a.account, a.password, a.name, a.role_id, a.status_id, a.create_time, a.update_time, a.create_user, a.update_user, b.name as create_user_name, c.name as update_user_name, d.name as status_name, e.name as role_name from tb_user as a left join tb_user as b on a.create_user = b.id left join tb_user as c on a.update_user = c.id left join tb_user_status as d on a.status_id = d.id left join tb_role as e on a.role_id = e.id where 1=1
and a.id = #{param.id}
and a.account = #{param.account}
and a.create_time >= #{param.createTimeMin}
and #{param.createTimeMax} >= a.create_time
and a.update_time >= #{param.updateTimeMin}
and #{param.updateTimeMax} >= a.update_time
